#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v;
    n->left = n->right = NULL;
    return n;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node** nodes = (Node**)malloc((N+1) * sizeof(Node*));
        bool* hasParent = (bool*)calloc(N+1, sizeof(bool));
        for (int i = 1; i <= N; ++i) nodes[i] = newNode(i);
        for (int i = 0; i < N-1; ++i) {
            int p, c; char R; scanf("%d %d %c", &p, &c, &R);
            if (R == 'L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
            hasParent[c] = true;
        }
        int rootVal = 1;
        for (int i = 1; i <= N; ++i) if (!hasParent[i]) { rootVal = i; break; }
        Node* root = nodes[rootVal];
        // BFS
        Node** q = (Node**)malloc((N+5) * sizeof(Node*));
        int front = 0, rear = 0;
        q[rear++] = root;
        while (front < rear) {
            Node* cur = q[front++];
            printf("%d", cur->val);
            if (front < rear) printf(" ");
            if (cur->left) q[rear++] = cur->left;
            if (cur->right) q[rear++] = cur->right;
        }
        printf("\n");
        free(q);
        free(nodes);
        free(hasParent);
    }
    return 0;
}

