import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        # nodes indexed by value (1..N)
        left = [0]*(N+1)
        right = [0]*(N+1)
        has_parent = [False]*(N+1)
        for __ in range(N-1):
            p,c,R = data[idx].split(); idx += 1
            p = int(p); c = int(c)
            if R == 'L':
                left[p] = c
            else:
                right[p] = c
            has_parent[c] = True
        root = 1
        for i in range(1,N+1):
            if not has_parent[i]:
                root = i
                break
        q = deque([root])
        order = []
        while q:
            node = q.popleft()
            order.append(str(node))
            if left[node]: q.append(left[node])
            if right[node]: q.append(right[node])
        out_lines.append(' '.join(order))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

