let output = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(lines[idx++].trim(), 10);
  const left = new Array(N + 1).fill(0);
  const right = new Array(N + 1).fill(0);
  const hasParent = new Array(N + 1).fill(false);
  for (let i = 0; i < N - 1; i++) {
    const [pStr, cStr, R] = lines[idx++].trim().split(' ');
    const p = parseInt(pStr, 10);
    const c = parseInt(cStr, 10);
    if (R === 'L') left[p] = c; else right[p] = c;
    hasParent[c] = true;
  }
  let root = 1;
  for (let i = 1; i <= N; i++) if (!hasParent[i]) { root = i; break; }
  const queue = [root];
  const order = [];
  while (queue.length) {
    const node = queue.shift();
    order.push(node);
    if (left[node]) queue.push(left[node]);
    if (right[node]) queue.push(right[node]);
  }
  output.push(order.join(' '));
}
